const input = $json || {};
const mapped_items = Array.isArray(input.mapped_items) ? input.mapped_items : [];
const zalo_user_id = String(input.zalo_user_id || '').trim();
if (!zalo_user_id) throw new Error('zalo_user_id required');
if (!mapped_items.length) return [{ json: { status: 'no_items', alerts: [] } }];
return [{ json: { mapped_items, zalo_user_id, invoice_meta: input.invoice_meta || {}, supplier_code: input.invoice_meta?.supplier_code || input.supplier_code || 'UNKNOWN_SUPPLIER' } }];

const ctx = $('Validate Input').item.json;
const rules = $('Load pricing_rules').all().map(i => i.json);
const cacheRows = $('Load product cache snapshot').all().map(i => i.json);
const cache = new Map(cacheRows.map(r => [Number(r.kiotviet_product_id), r]));

const selectRule = (productCode, supplierCode, categoryName) => {
  const active = rules.filter(r => r.is_active !== false);
  const pick = (type, key) => active
    .filter(r => r.rule_type === type && String(r.rule_key) === String(key))
    .sort((a,b)=>Number(b.priority||0)-Number(a.priority||0))[0];
  return pick('product', productCode)
    || pick('supplier', supplierCode)
    || pick('category', categoryName)
    || pick('category', 'DEFAULT')
    || { margin_percent: 15, rounding_rule: 'none', rule_key: 'DEFAULT', rule_type: 'category' };
};

const round = (v, rule) => {
  const n = Number(v || 0);
  if (rule === 'round_100') return Math.ceil(n/100)*100;
  if (rule === 'round_500') return Math.ceil(n/500)*500;
  if (rule === 'round_1000') return Math.ceil(n/1000)*1000;
  return Math.ceil(n);
};

const alerts = [];
for (const item of ctx.mapped_items) {
  const pid = Number(item.kiotviet_product_id || 0);
  if (!pid) continue;
  const cacheItem = cache.get(pid) || {};
  const new_cost = Number(item.converted_unit_price || item.unit_price || 0);
  const old_cost = Number(cacheItem.cost || 0);
  const current_price = Number(cacheItem.base_price || 0);
  const category = cacheItem.category_name || item.category_name || 'DEFAULT';
  const pcode = item.kiotviet_product_code || cacheItem.product_code || '';

  const rule = selectRule(pcode, ctx.supplier_code, category);
  const expected_min = round(new_cost * (1 + Number(rule.margin_percent || 0)/100), rule.rounding_rule || 'none');

  if (current_price < expected_min && new_cost > 0) {
    alerts.push({
      product_id: pid,
      product_code: pcode,
      product_name: cacheItem.product_name || item.item_name || pcode,
      old_cost,
      new_cost,
      current_price,
      expected_min,
      margin_percent: Number(rule.margin_percent || 0),
      rounding_rule: rule.rounding_rule || 'none'
    });
  }
}

return [{ json: { ...ctx, alerts } }];

const first = $json.alerts[0];
const text = `⚠️ Giá vốn tăng: ${first.product_name}
Giá vốn mới: ${first.new_cost.toLocaleString('vi-VN')}đ
Giá bán hiện tại: ${first.current_price.toLocaleString('vi-VN')}đ
Giá bán tối thiểu đề xuất: ${first.expected_min.toLocaleString('vi-VN')}đ`;
const payloadBase = `${first.product_id}|${first.expected_min}`;
return [{ json: { ...$json, zalo_message: {
  recipient: { user_id: $json.zalo_user_id },
  message: { text },
  buttons: [
    { title: '✅ Update suggested', payload: `PRICE_CONFIRM|${payloadBase}` },
    { title: '🔒 Keep', payload: `PRICE_KEEP|${payloadBase}` },
    { title: '✏️ Custom', payload: `PRICE_CUSTOM|${payloadBase}` }
  ]
} } }];
